-- Actualización de controles ISO 27001 por sector para Global ISO Security
-- Ejecutar una sola vez en TiDB/MySQL sobre la base globalisosecurity.
USE globalisosecurity;
SET FOREIGN_KEY_CHECKS = 0;
DELETE FROM evaluaciones WHERE item_checklist_id IN (SELECT id FROM items_checklist WHERE checklist_id IN (1,2,3,4));
DELETE FROM items_checklist WHERE checklist_id IN (1,2,3,4);
SET FOREIGN_KEY_CHECKS = 1;

UPDATE checklists SET descripcion = 'Checklist ISO 27001 dinámico para sector Salud' WHERE id = 1;
UPDATE checklists SET descripcion = 'Checklist ISO 27001 dinámico para sector Educación' WHERE id = 2;
UPDATE checklists SET descripcion = 'Checklist ISO 27001 dinámico para sector Financiero' WHERE id = 3;
UPDATE checklists SET descripcion = 'Checklist ISO 27001 dinámico para sector Tecnología' WHERE id = 4;

